import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"期权行情字段介绍","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-fields.md","filePath":"zh-CN/derivatives/options/options-fields.md"}'),l={name:"derivatives/options/options-fields.md"};function o(h,a,n,d,s,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="期权行情字段介绍" tabindex="-1">期权行情字段介绍 <a class="header-anchor" href="#期权行情字段介绍" aria-label="Permalink to &quot;期权行情字段介绍&quot;">​</a></h1><p>期权合约要素、希腊字母定义及其对期权价格的影响。</p><h2 id="合约要素" tabindex="-1">合约要素 <a class="header-anchor" href="#合约要素" aria-label="Permalink to &quot;合约要素&quot;">​</a></h2><h3 id="行权价" tabindex="-1">行权价 <a class="header-anchor" href="#行权价" aria-label="Permalink to &quot;行权价&quot;">​</a></h3><p>期权买方行权时适用的标的资产交易价格。</p><h3 id="到期日" tabindex="-1">到期日 <a class="header-anchor" href="#到期日" aria-label="Permalink to &quot;到期日&quot;">​</a></h3><p>期权合约的终止日，超过此日期合约失效。在美股市场中，股票周期权到期日为每周五，月期权到期日为每月第三个周五；指数期权可能在周中和周五都有到期日。</p><p>美式期权持有人在到期日之前任何时候都可以行权，欧式期权持有人只有在到期日才可以行权。</p><h3 id="合约乘数" tabindex="-1">合约乘数 <a class="header-anchor" href="#合约乘数" aria-label="Permalink to &quot;合约乘数&quot;">​</a></h3><p>每张期权合约对应的标的资产价值乘数。例如乘数为 100、行权价为 20，则合约价值为 100 × 20 = 2,000。</p><h3 id="合约规模" tabindex="-1">合约规模 <a class="header-anchor" href="#合约规模" aria-label="Permalink to &quot;合约规模&quot;">​</a></h3><p>每张期权合约对应的实际标的物数量，通常为 100（公司行动可能导致合约规模调整为非 100）。例如期权价格 0.5，一张期权权利金为 0.5 × 100 = 50。</p><h3 id="内在价值" tabindex="-1">内在价值 <a class="header-anchor" href="#内在价值" aria-label="Permalink to &quot;内在价值&quot;">​</a></h3><p>期权行权价与标的资产市场价格之间的差额，反映期权立即行使的潜在收益。</p><ul><li>看涨期权内在价值 = max(0, 标的现价 - 行权价)</li><li>看跌期权内在价值 = max(0, 行权价 - 标的现价)</li></ul><h3 id="时间价值" tabindex="-1">时间价值 <a class="header-anchor" href="#时间价值" aria-label="Permalink to &quot;时间价值&quot;">​</a></h3><p>期权总价值超出内在价值的部分，反映到期前的不确定性和潜在获利可能。时间价值随到期日临近逐渐衰减，至到期时变为零。</p><p>时间价值 = 期权市场价格 - 内在价值</p><h3 id="有效杠杆" tabindex="-1">有效杠杆 <a class="header-anchor" href="#有效杠杆" aria-label="Permalink to &quot;有效杠杆&quot;">​</a></h3><p>衡量期权合约对标的资产价格变动的敏感性与投资回报潜力，反映持有期权相较于直接持有标的资产的杠杆效应。</p><p>有效杠杆 = Delta × 标的资产价格 ÷ 期权价格</p><hr><h2 id="希腊字母" tabindex="-1">希腊字母 <a class="header-anchor" href="#希腊字母" aria-label="Permalink to &quot;希腊字母&quot;">​</a></h2><h3 id="隐含波动率-iv" tabindex="-1">隐含波动率（IV） <a class="header-anchor" href="#隐含波动率-iv" aria-label="Permalink to &quot;隐含波动率（IV）&quot;">​</a></h3><p>将期权价格带入期权定价模型（一般用 BS 模型）反推得到的标的资产波动性。IV 越高表示市场预期标的资产未来价格波动越大。</p><h3 id="delta" tabindex="-1">Delta <a class="header-anchor" href="#delta" aria-label="Permalink to &quot;Delta&quot;">​</a></h3><p>标的资产每变动 1 个单位，期权价格的变化量。</p><ul><li>看涨期权 Delta 在 0 到 1 之间</li><li>看跌期权 Delta 在 -1 到 0 之间</li><li>Delta 绝对值越大，期权价格对标的价格变动越敏感</li></ul><h3 id="gamma" tabindex="-1">Gamma <a class="header-anchor" href="#gamma" aria-label="Permalink to &quot;Gamma&quot;">​</a></h3><p>标的资产价格每变动 1 个单位，Delta 值的变化量。衡量 Delta 对标的价格变动的敏感程度。Gamma 越大，Delta 随价格变动越快。</p><h3 id="theta" tabindex="-1">Theta <a class="header-anchor" href="#theta" aria-label="Permalink to &quot;Theta&quot;">​</a></h3><p>距到期日每减少一天，期权价格的变化值。通常为负值，反映时间衰减对期权价格的侵蚀。越接近到期日，Theta 的绝对值通常越大。</p><h3 id="vega" tabindex="-1">Vega <a class="header-anchor" href="#vega" aria-label="Permalink to &quot;Vega&quot;">​</a></h3><p>标的资产价格波动率每变化 1%，对期权价格的影响。Vega 越大，期权价格对波动率变化越敏感。</p><h3 id="rho" tabindex="-1">Rho <a class="header-anchor" href="#rho" aria-label="Permalink to &quot;Rho&quot;">​</a></h3><p>无风险利率变动 1% 对期权价格的影响程度。通常影响较小，在利率环境变化较大时需要关注。</p>',36)])])}const m=e(l,[["render",o]]);export{u as __pageData,m as default};
